package br.com.samuel.stockly;import android.app.*;import android.content.*;import android.os.*;import android.text.*;import android.widget.*;
public class ProductFormActivity extends Activity{static final String ID="id";long id=-1;EditText name,price,qty,min,cat;ProductRepository repo;Session s;static Intent intent(Context c,long id){return new Intent(c,ProductFormActivity.class).putExtra(ID,id);}protected void onCreate(Bundle b){super.onCreate(b);s=new Session(this);repo=new ProductRepository(new DB(this));id=getIntent().getLongExtra(ID,-1);ScrollView sv=new ScrollView(this);LinearLayout r=Ui.root(this);sv.addView(r);Ui.add(r,Ui.tv(this,id>0?"Editar produto":"Novo produto",24,true,Ui.TEXT));name=Ui.input(this,"Nome");price=Ui.input(this,"Preço");price.setInputType(InputType.TYPE_CLASS_NUMBER|InputType.TYPE_NUMBER_FLAG_DECIMAL);qty=Ui.input(this,"Quantidade");qty.setInputType(InputType.TYPE_CLASS_NUMBER);min=Ui.input(this,"Estoque mínimo");min.setInputType(InputType.TYPE_CLASS_NUMBER);cat=Ui.input(this,"Categoria");Button save=Ui.btn(this,"Salvar",Ui.BLUE,0xffffffff),back=Ui.btn(this,"Voltar",0xffffffff,Ui.BLUE);Ui.addM(r,name,10);Ui.addM(r,price,8);Ui.addM(r,qty,8);Ui.addM(r,min,8);Ui.addM(r,cat,8);Ui.addM(r,save,14);Ui.addM(r,back,8);setContentView(sv);if(id>0)load();save.setOnClickListener(v->save());back.setOnClickListener(v->finish());}void load(){Product p=repo.find(id);if(p==null){finish();return;}name.setText(p.name);price.setText(""+p.price);qty.setText(""+p.qty);min.setText(""+p.min);cat.setText(p.cat);}void save(){try{String n=name.getText().toString(),c=cat.getText().toString().trim().isEmpty()?"Geral":cat.getText().toString();double pr=Double.parseDouble(price.getText().toString().replace(',','.'));int q=Integer.parseInt(qty.getText().toString()),m=min.getText().toString().trim().isEmpty()?1:Integer.parseInt(min.getText().toString());if(n.trim().isEmpty()||pr<0||q<0||m<0){toast("Verifique os campos");return;}repo.save(id,s.id(),n,pr,q,m,c);toast("Produto salvo");finish();}catch(Exception e){toast("Valores inválidos");}}void toast(String m){Toast.makeText(this,m,Toast.LENGTH_SHORT).show();}}
